xsl:template.script:
		$(document).ready(function(){
	var oi_legajo = $("#oi_personal_emp").attr("value");
	SetParam("oi_legajo",oi_legajo);
});

function SetParam(param,valor){
	this.parent.SetParam(param,valor);
}

function BlanquearParam(name){
	//Desabilito el btn aceptar
	this.parent.EnabledBtnSend(false);
	//Desabilito todos los radio y habilito solamente el que tengo seleccioanado
	$("input[type=radio]").prop("disabled", true);
	$("#"+name).prop("disabled", false);
	//Selecciono el radio del legajo.
	$("#"+name).prop("checked", true);
	//Seteo el valor del legajo que iniciara el WF
	var legajo = name.substr(7);
	this.SetParam("oi_legajo",legajo);
	//Seteo la liquidacion a undefined
	this.SetParam("oi_liquidacion",undefined);
	//Saco el tilde a la fila que este seleccionada en el momento
	$('img.img-tilde').hide();
}

function BlanquearParam2(id){
	var legajo = id.substr(8);

	//Desabilito el btn aceptar
	this.parent.EnabledBtnSend(false);

	//Desabilito todos los radio y habilito solamente el que tengo seleccioanado
	$("input[type=radio]").prop("disabled", true);
	$("#legajo_"+legajo).prop("disabled", false);

	//Selecciono el radio del legajo.
	$("#legajo_"+legajo).prop("checked", true);

	//Seteo el valor del legajo que iniciara el WF
	this.SetParam("oi_legajo",legajo);            

	//Seteo la liquidacion a undefined
	this.SetParam("oi_liquidacion",undefined);
	//Saco el tilde a la fila que este seleccionada en el momento
	$('img.img-tilde').hide();
}

function selectRecibo(nameLiq){
	$('img.img-tilde').hide();
	$('#'+nameLiq+' td:first img').show();

	this.parent.EnabledBtnSend(true);

	var id_liq = nameLiq.substr(15);
	this.SetParam("oi_liquidacion", id_liq);
}

html:xslt.xsl:template:
		#reciboSueldo{
	margin-top: 10px;
}

#panel-recibos{
	margin:auto;
	width:70%;
}          

#table-recibos tbody tr{
	cursor:pointer;
}

.img-tilde{
	width: 23px;
	margin: auto;
}

#table-recibos tbody tr td, #table-recibos thead tr th{
	text-align: center;
}

.radio-legajo{
float:right!important;
}

.pointer{
	cursor: pointer;
}
